namespace sv_0e427d3e8c9541d3885307b735b16500.Services;

public record WarehouseInfo(string Id, string Name)
{
    public static readonly WarehouseInfo[] All =
    [
        new("WH1", "Warehouse A"),
        new("WH2", "Warehouse B"),
        new("WH3", "Warehouse C"),
    ];

    public static readonly WarehouseInfo Default = All[0];
}

using Microsoft.AspNetCore.Components;

namespace sv_0e427d3e8c9541d3885307b735b16500.Services;

/// <summary>
/// Scoped service that holds the current warehouse selection and low-stock alert count.
/// Each Blazor Server circuit (i.e., each browser tab) gets its own instance,
/// so managers never interfere with each other.
/// </summary>
public sealed class WarehouseState
{
    private WarehouseInfo _current = WarehouseInfo.Default;

    /// <summary>
    /// Exposed as a DI-registered cascading value so every component can receive
    /// the current warehouse via <c>[CascadingParameter]</c> without injecting this service.
    /// </summary>
    public CascadingValueSource<WarehouseInfo> WarehouseSource { get; }

    public WarehouseInfo Current => _current;

    private int _lowStockCount;
    public int LowStockCount => _lowStockCount;

    /// <summary>
    /// Raised when <see cref="LowStockCount"/> changes so that the sidebar badge
    /// (which lives outside the polling page) can re-render.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public WarehouseState()
    {
        // The factory overload lets NotifyChangedAsync re-evaluate the current value.
        WarehouseSource = new CascadingValueSource<WarehouseInfo>(() => _current, isFixed: false);
    }

    public async Task SetWarehouseAsync(WarehouseInfo warehouse)
    {
        _current = warehouse;
        _lowStockCount = 0;
        OnAlertCountChanged?.Invoke();
        await WarehouseSource.NotifyChangedAsync();
    }

    public void UpdateLowStockCount(int count)
    {
        if (_lowStockCount == count) return;
        _lowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

namespace sv_0e427d3e8c9541d3885307b735b16500.Services;

/// <summary>
/// Simulates a database query that returns how many items in a given warehouse
/// are below their minimum stock level.
/// </summary>
public sealed class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }
}

