@page "/dashboard"
@rendermode InteractiveServer
@using sv_0e427d3e8c9541d3885307b735b16500.Services
@implements IAsyncDisposable
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard — @_currentWarehouse.Name</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4 g-3">
    <div class="col-md-4">
        <div class="card h-100">
            <div class="card-body">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@_currentWarehouse.Name</p>
                <p class="text-muted mb-0">ID: @_currentWarehouse.Id</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card h-100 @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-1 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="text-muted mb-0">Items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card h-100">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text">
                    <span class="badge bg-success">Active</span>
                    <span class="text-muted ms-2">every 10 s</span>
                </p>
                <p class="text-muted mb-0">Last checked: @_lastChecked.ToString("T")</p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter(Name = "CurrentWarehouse")]
    private WarehouseInfo _currentWarehouse { get; set; } = WarehouseInfo.Default;

    private int _lowStockCount;
    private DateTime _lastChecked = DateTime.Now;
    private string? _previousWarehouseId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (_currentWarehouse.Id == _previousWarehouseId)
            return;

        _previousWarehouseId = _currentWarehouse.Id;
        await RestartPollingAsync();
    }

    private async Task RestartPollingAsync()
    {
        await StopPollingAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        await FetchAlertCountAsync();
        _ = PollAsync(token);
    }

    private async Task FetchAlertCountAsync()
    {
        _lowStockCount = await AlertService.GetLowStockCountAsync(_currentWarehouse.Id);
        _lastChecked = DateTime.Now;
        WarehouseState.UpdateLowStockCount(_lowStockCount);
    }

    private async Task PollAsync(CancellationToken token)
    {
        try
        {
            using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            while (await timer.WaitForNextTickAsync(token))
            {
                await FetchAlertCountAsync();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when navigating away or switching warehouses
        }
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopPollingAsync();
    }
}

